-- Seed: daily_cards
-- All 365 days. Every row has BOTH an affirmation and a journal_prompt (reflection).
-- Gray "Act with Intention" / practice cards additionally carry a body_text instruction.
-- Idempotent: upserts on day_number. Re-run safely.
--
-- Visual cycle within each month repeats every 5 days:
--   purple woman  -> #2a1e3f (affirmation lead)
--   red pencil    -> #a8201f (reflection lead)
--   gray badge    -> #8a8a85 (practice in body_text + affirmation + reflection)
--   green mandala -> #1f5c3a (reflection lead)
--   gold varies   -> #b8922a (affirmation lead)
--
-- Months: Jan Alignment, Feb Self-Love, Mar Boundaries, Apr Inner Peace,
-- May Confidence, Jun Healing, Jul Freedom, Aug Manifestation, Sep Mindset,
-- Oct Reinvention, Nov Gratitude, Dec Wholeness.

insert into public.daily_cards
  (day_number, theme, title, body_text, affirmation, journal_prompt, image_url, card_color, emoji)
values
  -- January: Alignment
  (  1, 'Alignment', 'Peace, Power, Purpose',          null, 'I align with peace, power, and divine purpose.', 'Where in your life do you feel most in alignment right now?', '/cards/card-1.png',  '#2a1e3f', null),
  (  2, 'Alignment', 'Alignment in the Body',          null, 'I trust the signals my body sends me.', 'What does alignment feel like in your body?', '/cards/card-2.png',  '#a8201f', null),
  (  3, 'Alignment', 'Three Breaths',                  'Take 3 deep breaths before you check your phone today.', 'I begin each day with intention, not reaction.', 'How does the way you start your morning shape your day?', '/cards/card-3.png',  '#8a8a85', null),
  (  4, 'Alignment', 'Let It Go',                      null, 'I release what is not mine to carry.', 'What do you need to let go of to come into alignment?', '/cards/card-4.png',  '#1f5c3a', null),
  (  5, 'Alignment', 'Peace Is Your Compass',          null, 'Your peace is your compass. Trust where it leads you.', 'When was the last time peace guided one of your decisions?', '/cards/card-5.png',  '#b8922a', null),
  (  6, 'Alignment', 'Divine Timing',                  null, 'I am walking in divine timing and intentional direction.', 'Where are you being asked to trust the timing instead of forcing it?', '/cards/card-6.png',  '#2a1e3f', null),
  (  7, 'Alignment', 'Forcing vs. Flowing',            null, 'I choose ease over effort whenever ease is available.', 'Where have you been forcing instead of flowing?', '/cards/card-7.png',  '#a8201f', null),
  (  8, 'Alignment', 'First Glass of Water',           'Drink a full glass of water before beginning your day.', 'I tend to my body the way I tend to my dreams.', 'What small acts of care do you skip when you''re rushing?', '/cards/card-8.png',  '#8a8a85', null),
  (  9, 'Alignment', 'A Well-Aligned Day',             null, 'My days reflect what matters most to me.', 'What does a well-aligned day look like for you?', '/cards/card-9.png',  '#1f5c3a', null),
  ( 10, 'Alignment', 'Easy Doors',                     null, 'When you''re aligned, the right doors open without force.', 'What door has opened easily that you can finally walk through?', '/cards/card-10.png', '#b8922a', null),
  ( 11, 'Alignment', 'Honor the Pace',                 null, 'I honor the pace of my journey.', 'Whose timeline have you been measuring yourself against?', '/cards/card-11.png', '#2a1e3f', null),
  ( 12, 'Alignment', 'Out of Sync',                    null, 'I notice misalignment without judging myself for it.', 'In what area of your life do you feel out of sync?', '/cards/card-12.png', '#a8201f', null),
  ( 13, 'Alignment', 'Candle and Center',              'Light a candle or incense and center yourself this morning.', 'I create sacred space inside my ordinary day.', 'What ritual could ground you when life feels scattered?', '/cards/card-13.png', '#8a8a85', null),
  ( 14, 'Alignment', 'When Things Don''t Go',          null, 'I stay open even when the plan changes.', 'How do you respond when things don''t go as planned?', '/cards/card-14.png', '#1f5c3a', null),
  ( 15, 'Alignment', 'Presence Over Perfection',       null, 'Alignment isn''t about perfection; it''s about presence.', 'Where has chasing perfection cost you presence?', '/cards/card-15.png', '#b8922a', null),
  ( 16, 'Alignment', 'Thoughts, Words, Actions',       null, 'My thoughts, words, and actions align with my purpose.', 'Which one — thoughts, words, or actions — needs realigning?', '/cards/card-16.png', '#2a1e3f', null),
  ( 17, 'Alignment', 'Distractions',                   null, 'I protect my focus the way I protect my peace.', 'What distractions are keeping you misaligned?', '/cards/card-17.png', '#a8201f', null),
  ( 18, 'Alignment', 'Morning Stretch',                'Stretch your body for 3 minutes after waking up.', 'I move my body in ways that thank it.', 'How does your body feel different when you greet it gently?', '/cards/card-18.png', '#8a8a85', null),
  ( 19, 'Alignment', 'Aligned Relationships',          null, 'I am drawn to people who reflect my growth back to me.', 'What would alignment look like in your relationships?', '/cards/card-19.png', '#1f5c3a', null),
  ( 20, 'Alignment', 'Choose It Daily',                null, 'You can''t chase alignment; you must choose it daily.', 'What small choice today would put you back in alignment?', '/cards/card-20.png', '#b8922a', null),
  ( 21, 'Alignment', 'Grounded in Becoming',           null, 'I am grounded in who I am and who I''m becoming.', 'What do you know about yourself today that you didn''t a year ago?', '/cards/card-21.png', '#2a1e3f', null),
  ( 22, 'Alignment', 'Identity Redefined',             null, 'I am free to redefine who I am whenever I choose.', 'What part of your identity needs redefining?', '/cards/card-22.png', '#a8201f', null),
  ( 23, 'Alignment', 'Intention Before Scroll',        'Set one small intention before checking social media.', 'I enter the noise from a grounded place.', 'How does your morning shift when intention comes before input?', '/cards/card-23.png', '#8a8a85', null),
  ( 24, 'Alignment', 'Never Settle',                   null, 'I refuse to call comfort what I really mean by stuck.', 'Where are you settling for a familiar norm instead of alignment?', '/cards/card-24.png', '#1f5c3a', null),
  ( 25, 'Alignment', 'Doesn''t Shrink',                null, 'The version of you who''s in alignment doesn''t shrink.', 'Where have you been shrinking to fit a smaller story?', '/cards/card-25.png', '#b8922a', null),
  ( 26, 'Alignment', 'Permission to Move Differently', null, 'I give myself permission to move differently.', 'What would change if you stopped moving how others expected?', '/cards/card-26.png', '#2a1e3f', null),
  ( 27, 'Alignment', 'Routines to Rebuild',            null, 'I build the rhythms that build me.', 'What routines do you need to rebuild?', '/cards/card-27.png', '#a8201f', null),
  ( 28, 'Alignment', 'Three Aligned Actions',          'Write down 3 aligned actions for your goals today.', 'I move my goals forward through small, aligned steps.', 'Which of today''s aligned actions felt the most natural?', '/cards/card-28.png', '#8a8a85', null),
  ( 29, 'Alignment', 'Habits That Support You',        null, 'My habits are honest votes for the woman I''m becoming.', 'What habits support your alignment? What habits don''t?', '/cards/card-29.png', '#1f5c3a', null),
  ( 30, 'Alignment', 'Unstoppable Momentum',           null, 'Consistency in alignment creates unstoppable momentum.', 'Where is your consistency quietly compounding right now?', '/cards/card-30.png', '#b8922a', null),
  ( 31, 'Alignment', 'Trust the Process',              null, 'I trust the process, even when it''s unclear.', 'What part of your process is asking for trust right now?', '/cards/card-31.png', '#2a1e3f', null),
  -- February: Self-Love
  ( 32, 'Self-Love', 'Worthy of Love',                 null, 'I am worthy of the love I give so freely to others.', 'Where do you give love freely but receive it reluctantly?', '/cards/card-32.png', '#2a1e3f', null),
  ( 33, 'Self-Love', 'Parts Waiting to Be Loved',      null, 'I love the parts of me that haven''t been loved yet.', 'What parts of yourself are still waiting to be loved?', '/cards/card-33.png', '#a8201f', null),
  ( 34, 'Self-Love', 'Self-Hug',                       'Start your day with a self-hug and a kind word to yourself.', 'I am the first person to receive my care today.', 'What kind word would mean the most to hear from yourself?', '/cards/card-34.png', '#8a8a85', null),
  ( 35, 'Self-Love', 'Definition of Love',             null, 'I rewrite my definition of love until it loves me back.', 'Where did you learn your definition of love, and does it still serve you?', '/cards/card-35.png', '#1f5c3a', null),
  ( 36, 'Self-Love', 'Spiritual Alignment',            null, 'Self-love isn''t selfish; it''s spiritual alignment.', 'What changes when you stop calling self-love selfish?', '/cards/card-36.png', '#b8922a', null),
  ( 37, 'Self-Love', 'Take Up Space',                  null, 'I am allowed to take up space and be seen.', 'Where have you made yourself smaller to be more comfortable to others?', '/cards/card-37.png', '#2a1e3f', null),
  ( 38, 'Self-Love', 'Letter to Younger Self',         null, 'My younger self is proud of who I''m becoming.', 'Write a love letter to your younger self.', '/cards/card-38.png', '#a8201f', null),
  ( 39, 'Self-Love', 'Compliment Aloud',               'Compliment yourself aloud before stepping out today.', 'I speak well of myself even when no one is listening.', 'What''s a compliment you''ve never let yourself accept?', '/cards/card-39.png', '#8a8a85', null),
  ( 40, 'Self-Love', 'The Love You Crave',             null, 'I give myself the love I''ve been asking others to provide.', 'What does it look like to treat yourself with the love you crave from others?', '/cards/card-40.png', '#1f5c3a', null),
  ( 41, 'Self-Love', 'The Right Amount',               null, 'You are not too much. You are the right amount for the right people.', 'Who has called you ''too much'' for what was actually their limit?', '/cards/card-41.png', '#b8922a', null),
  ( 42, 'Self-Love', 'Grace, Not Guilt',               null, 'I choose to give myself grace, not guilt.', 'Where has guilt been masquerading as accountability?', '/cards/card-42.png', '#2a1e3f', null),
  ( 43, 'Self-Love', 'Most Like You',                  null, 'I return to myself easily.', 'What makes you feel most like you?', '/cards/card-43.png', '#a8201f', null),
  ( 44, 'Self-Love', 'Gratitude Meditation',           'Start the day with a 2-minute gratitude meditation.', 'Gratitude is my first language each morning.', 'What would two minutes of gratitude unlock in your day?', '/cards/card-44.png', '#8a8a85', null),
  ( 45, 'Self-Love', 'Celebrate Yourself',             null, 'I celebrate myself before anyone else has the chance.', 'When was the last time you truly celebrated yourself?', '/cards/card-45.png', '#1f5c3a', null),
  ( 46, 'Self-Love', 'Revolutionary Act',              null, 'Loving yourself is a revolutionary act.', 'What does the world gain when you love yourself fully?', '/cards/card-46.png', '#b8922a', null),
  ( 47, 'Self-Love', 'Deeply and Completely',          null, 'I love myself deeply, completely, and unapologetically.', 'What does unapologetic self-love require of you?', '/cards/card-47.png', '#2a1e3f', null),
  ( 48, 'Self-Love', 'Honor Your Needs',               null, 'My needs are not negotiable.', 'What''s one way you can honor your needs today?', '/cards/card-48.png', '#a8201f', null),
  ( 49, 'Self-Love', 'Three Things You Love',          'Write down three things you love about your personality.', 'I love who I am, not just what I do.', 'Which trait of yours do you forget to appreciate?', '/cards/card-49.png', '#8a8a85', null),
  ( 50, 'Self-Love', 'Self-Love Daily',                null, 'I am the daily priority I have always been waiting for.', 'What would your life look like if you prioritized self-love daily?', '/cards/card-50.png', '#1f5c3a', null),
  ( 51, 'Self-Love', 'The Standard',                   null, 'Your love for yourself sets the standard for every other relationship.', 'What standard are your relationships meeting because you set it for yourself?', '/cards/card-51.png', '#b8922a', null),
  ( 52, 'Self-Love', 'Already Enough',                 null, 'I release the need to earn love; I am already enough.', 'Where are you still trying to earn love that''s already yours?', '/cards/card-52.png', '#2a1e3f', null),
  ( 53, 'Self-Love', 'Abandoned Yourself',             null, 'I come back to myself, again and again.', 'In what ways have you abandoned yourself?', '/cards/card-53.png', '#a8201f', null),
  ( 54, 'Self-Love', 'Solo Date',                      'Take yourself on a solo date this week.', 'My own company is enough.', 'What kind of date would your soul thank you for?', '/cards/card-54.png', '#8a8a85', null),
  ( 55, 'Self-Love', 'When You Make a Mistake',        null, 'I speak to myself the way I would speak to someone I love.', 'How do you talk to yourself when you make a mistake?', '/cards/card-55.png', '#1f5c3a', null),
  ( 56, 'Self-Love', 'Already Whole',                  null, 'You don''t have to shrink to be accepted. You are already whole.', 'Where have you shrunk to fit, and what did you lose in the bargain?', '/cards/card-56.png', '#b8922a', null),
  ( 57, 'Self-Love', 'Love in Human Form',             null, 'I am love in human form.', 'Where do you most often forget that you are love?', '/cards/card-57.png', '#2a1e3f', null),
  ( 58, 'Self-Love', 'Loving Boundaries',              null, 'My boundaries are how love gets to stay.', 'What are five loving boundaries you want to practice?', '/cards/card-58.png', '#a8201f', null),
  ( 59, 'Self-Love', 'Mirror Truth',                   'Look in the mirror and speak truth to the woman staring back.', 'The woman in the mirror is on my side.', 'What truth has she been waiting to hear from you?', '/cards/card-59.png', '#8a8a85', null),
  ( 60, 'Self-Love', 'Kindest Thing',                  null, 'I am the kindest voice in my own head.', 'What is the kindest thing you''ve done for yourself lately?', '/cards/card-60.png', '#1f5c3a', null),
  ( 61, 'Self-Love', 'Starts With You',                null, 'You deserve a love that starts with you.', 'If love started with you today, where would you direct it first?', '/cards/card-61.png', '#b8922a', null),
  -- March: Boundaries
  ( 62, 'Boundaries', 'Sacred Boundaries',             null, 'I honor my energy by setting sacred boundaries.', 'What boundary, once spoken, would change your life?', '/cards/card-62.png', '#2a1e3f', null),
  ( 63, 'Boundaries', 'Yes vs. No',                    null, 'My yes is golden because my no is honest.', 'Where in your life are you saying ''yes'' when you mean ''no''?', '/cards/card-63.png', '#a8201f', null),
  ( 64, 'Boundaries', 'Say No Today',                  'Say ''no'' to something today that doesn''t serve you.', 'No is a complete sentence I am allowed to use.', 'Whose disappointment have you been managing instead of your own no?', '/cards/card-64.png', '#8a8a85', null),
  ( 65, 'Boundaries', 'Improved by a Boundary',        null, 'My boundaries don''t ruin relationships; they reveal them.', 'What relationship would improve if you enforced a boundary?', '/cards/card-65.png', '#1f5c3a', null),
  ( 66, 'Boundaries', 'Mirror of Self-Respect',        null, 'Your boundaries are a reflection of your self-respect.', 'What does your boundary list say about how you see yourself?', '/cards/card-66.png', '#b8922a', null),
  ( 67, 'Boundaries', 'Release the Guilt',             null, 'I release guilt when I protect my peace.', 'Where has guilt been the price of your boundaries?', '/cards/card-67.png', '#2a1e3f', null),
  ( 68, 'Boundaries', 'Drained After Giving',          null, 'I give from overflow, not from obligation.', 'What makes you feel drained after giving?', '/cards/card-68.png', '#a8201f', null),
  ( 69, 'Boundaries', 'Pause Before Responding',       'Pause before responding to a request today. Check in with yourself first.', 'I am allowed to need time before I answer.', 'What would change if ''let me think about it'' became your default?', '/cards/card-69.png', '#8a8a85', null),
  ( 70, 'Boundaries', 'Afraid to Set',                 null, 'I name what I need without fear of being unloved for it.', 'What boundary have you been afraid to set?', '/cards/card-70.png', '#1f5c3a', null),
  ( 71, 'Boundaries', 'No Is a Complete Sentence',     null, 'No is a complete sentence.', 'What no have you been over-explaining when no was already enough?', '/cards/card-71.png', '#b8922a', null),
  ( 72, 'Boundaries', 'Bold Enough',                   null, 'I am bold enough to protect what I value.', 'What do you value enough to be inconvenient for?', '/cards/card-72.png', '#2a1e3f', null),
  ( 73, 'Boundaries', 'Boldness Right Now',            null, 'Boldness is just honesty I haven''t postponed.', 'What does boldness look like in your life right now?', '/cards/card-73.png', '#a8201f', null),
  ( 74, 'Boundaries', 'Bold Declaration',              'Start your day with a bold declaration of who you are.', 'I name myself before the world tries to.', 'What declaration would you make if no one could push back?', '/cards/card-74.png', '#8a8a85', null),
  ( 75, 'Boundaries', 'Proud of Being Direct',         null, 'Being direct is how I love myself out loud.', 'When have you been proud of yourself for being direct?', '/cards/card-75.png', '#1f5c3a', null),
  ( 76, 'Boundaries', 'Your Whole Self',               null, 'The boldest thing you can be is your whole self.', 'Which version of yourself are you ready to bring everywhere?', '/cards/card-76.png', '#b8922a', null),
  ( 77, 'Boundaries', 'No Longer Overextend',          null, 'I no longer overextend myself to be liked.', 'Where has overextending cost you more than being disliked would have?', '/cards/card-77.png', '#2a1e3f', null),
  ( 78, 'Boundaries', 'Release People-Pleasing',       null, 'I am safe to disappoint people in service of my truth.', 'What part of people-pleasing are you ready to release?', '/cards/card-78.png', '#a8201f', null),
  ( 79, 'Boundaries', 'Calendar Audit',                'Check your calendar — remove one thing that doesn''t feel aligned.', 'My time is the truest measure of my values.', 'What does your calendar say you actually believe in?', '/cards/card-79.png', '#8a8a85', null),
  ( 80, 'Boundaries', 'Bold Truth, Quiet Suffering',   null, 'I trade quiet suffering for honest discomfort.', 'How would your life change if you chose bold truth over quiet suffering?', '/cards/card-80.png', '#1f5c3a', null),
  ( 81, 'Boundaries', 'Power Back',                    null, 'Every boundary you set gives you your power back.', 'Where did your power leak out, and which boundary would seal it?', '/cards/card-81.png', '#b8922a', null),
  ( 82, 'Boundaries', 'Not Born to Shrink',            null, 'I was not born to shrink or silence myself.', 'Where have you mistaken silence for safety?', '/cards/card-82.png', '#2a1e3f', null),
  ( 83, 'Boundaries', 'The Bold Move',                 null, 'The move I''m afraid of is usually the one I''m meant to make.', 'What''s one bold move you''ve been hesitating to make?', '/cards/card-83.png', '#a8201f', null),
  ( 84, 'Boundaries', 'Free Yourself',                 'Say something today you''ve been holding in. Free yourself.', 'What I say honestly cannot ruin what was real.', 'What truth has been costing you peace by staying inside?', '/cards/card-84.png', '#8a8a85', null),
  ( 85, 'Boundaries', 'Fear and Power',                null, 'My power is not waiting for the fear to leave.', 'What fear is keeping you from fully standing in your power?', '/cards/card-85.png', '#1f5c3a', null),
  ( 86, 'Boundaries', 'Disrupt and Shine',             null, 'You were not made to dim. You were made to disrupt and shine.', 'Whose comfort have you been dimming yourself to protect?', '/cards/card-86.png', '#b8922a', null),
  ( 87, 'Boundaries', 'Honoring My Needs',             null, 'I am proud of myself for honoring my needs.', 'Which need did you finally start honoring this year?', '/cards/card-87.png', '#2a1e3f', null),
  ( 88, 'Boundaries', 'Non-Negotiables',               null, 'My non-negotiables are how I keep my promises to myself.', 'Write out your non-negotiables and revisit them often.', '/cards/card-88.png', '#a8201f', null),
  ( 89, 'Boundaries', 'Speak Boldly',                  'Speak boldly about your desires today, even if it feels uncomfortable.', 'My desires deserve to be said out loud.', 'What desire have you been hinting at instead of naming?', '/cards/card-89.png', '#8a8a85', null),
  ( 90, 'Boundaries', 'Stop Apologizing',              null, 'I take up space without apology.', 'What would it look like to stop apologizing for existing?', '/cards/card-90.png', '#1f5c3a', null),
  ( 91, 'Boundaries', 'Highest Form of Self-Love',     null, 'Protecting your boundaries is the highest form of self-love.', 'Where will you protect your peace this week without explanation?', '/cards/card-91.png', '#b8922a', null),
  -- April: Inner Peace
  ( 92, 'Inner Peace', 'Peace as Priority',            null, 'Peace is my priority and my power.', 'What would change if peace were your top priority this month?', '/cards/card-92.png', '#2a1e3f', null),
  ( 93, 'Inner Peace', 'Peace in the Body',            null, 'My body recognizes peace and remembers how to return to it.', 'What does peace feel like in your body, and how often do you feel it?', '/cards/card-93.png', '#a8201f', null),
  ( 94, 'Inner Peace', 'Three Minutes of Silence',     'Sit in silence for 3 minutes before starting your day.', 'Silence is where I hear myself again.', 'What does your mind say when you stop filling it?', '/cards/card-94.png', '#8a8a85', null),
  ( 95, 'Inner Peace', 'Release for Peace',            null, 'I release what disturbs my peace, even when it''s familiar.', 'What do you need to release to welcome peace?', '/cards/card-95.png', '#1f5c3a', null),
  ( 96, 'Inner Peace', 'Honoring Your Worth',          null, 'Protecting your peace is honoring your worth.', 'Where does protecting your peace feel like a form of self-respect?', '/cards/card-96.png', '#b8922a', null),
  ( 97, 'Inner Peace', 'Calm Over Chaos',              null, 'I choose calm over chaos, every time.', 'What chaos have you mistaken for productivity?', '/cards/card-97.png', '#2a1e3f', null),
  ( 98, 'Inner Peace', 'Pulled Out of Peace',          null, 'I notice what disturbs my peace without becoming it.', 'What situations or people pull you out of peace?', '/cards/card-98.png', '#a8201f', null),
  ( 99, 'Inner Peace', 'Notifications Off',            'Turn off notifications for 1 hour today.', 'I decide when I am available, not the world.', 'How does your mood shift in the first hour without alerts?', '/cards/card-99.png', '#8a8a85', null),
  (100, 'Inner Peace', 'Nervous System',               null, 'I listen to my nervous system before I push past it.', 'What does your nervous system need right now?', '/cards/card-100.png', '#1f5c3a', null),
  (101, 'Inner Peace', 'Powerful Choice',              null, 'Peace is not passive. It''s a powerful choice.', 'Where does peace require effort that no one will see?', '/cards/card-101.png', '#b8922a', null),
  (102, 'Inner Peace', 'When the World Gets Loud',     null, 'I return to myself when the world gets loud.', 'Where do you go inside yourself when the noise rises?', '/cards/card-102.png', '#2a1e3f', null),
  (103, 'Inner Peace', 'Re-Center',                    null, 'I have everything I need to come back to center.', 'What helps you re-center when you''re overwhelmed?', '/cards/card-103.png', '#a8201f', null),
  (104, 'Inner Peace', 'Warm and Slow',                'Drink something warm slowly. Be present with every sip.', 'I move at the speed of presence.', 'What do you taste when you actually slow down?', '/cards/card-104.png', '#8a8a85', null),
  (105, 'Inner Peace', 'Stealing Your Peace',          null, 'Nothing has access to my peace without my consent.', 'What''s stealing your peace without your permission?', '/cards/card-105.png', '#1f5c3a', null),
  (106, 'Inner Peace', 'Still and Strong',             null, 'You can be still and strong at the same time.', 'Where has rest looked like weakness to you, and was it really?', '/cards/card-106.png', '#b8922a', null),
  (107, 'Inner Peace', 'Permission to Pause',          null, 'I give myself permission to pause.', 'What were you taught about pausing that you''re ready to unlearn?', '/cards/card-107.png', '#2a1e3f', null),
  (108, 'Inner Peace', 'Slow vs. Rush',                null, 'Slow is a pace I can sustain.', 'Where can you slow down instead of rushing today?', '/cards/card-108.png', '#a8201f', null),
  (109, 'Inner Peace', 'Breath Between Tasks',         'Take 3 deep breaths every time you switch tasks today.', 'I carry stillness between every action.', 'What changes between tasks when you bring breath with you?', '/cards/card-109.png', '#8a8a85', null),
  (110, 'Inner Peace', 'Turn Down the Noise',          null, 'I turn the volume down on whatever drowns out my thinking.', 'What noise in your life needs to be turned down?', '/cards/card-110.png', '#1f5c3a', null),
  (111, 'Inner Peace', 'Sacred Stillness',             null, 'Stillness is a sacred practice, not a waste of time.', 'Whose voice told you stillness was lazy, and is that voice still right?', '/cards/card-111.png', '#b8922a', null),
  (112, 'Inner Peace', 'Rooted in Peace',              null, 'I am rooted in peace, not pressure.', 'Where have you confused pressure with purpose?', '/cards/card-112.png', '#2a1e3f', null),
  (113, 'Inner Peace', 'Most at Peace',                null, 'Peace with myself is my home base.', 'When do you feel most at peace with yourself?', '/cards/card-113.png', '#a8201f', null),
  (114, 'Inner Peace', 'Five Minutes Outside',         'Spend 5 minutes outside today, observing nature.', 'Nature reminds me what unhurried looks like.', 'What does your body do differently outside than inside?', '/cards/card-114.png', '#8a8a85', null),
  (115, 'Inner Peace', 'Inner World Check-In',         null, 'I am as attentive to my inner world as I am to my calendar.', 'How often do you check in with your inner world?', '/cards/card-115.png', '#1f5c3a', null),
  (116, 'Inner Peace', 'Peace Over Pace',              null, 'Let go of urgency. Your peace matters more than your pace.', 'What false urgency have you been honoring at the cost of your peace?', '/cards/card-116.png', '#b8922a', null),
  (117, 'Inner Peace', 'Atmosphere of Calm',           null, 'I create an atmosphere of calm within me.', 'What makes someone feel calmer in your presence?', '/cards/card-117.png', '#2a1e3f', null),
  (118, 'Inner Peace', 'Peace as Default',             null, 'Peace is not a reward for finishing; it''s how I move.', 'What would your life feel like if peace was your default?', '/cards/card-118.png', '#a8201f', null),
  (119, 'Inner Peace', 'Calming Music',                'Play calming music during your morning routine.', 'I score my mornings with what soothes me.', 'How does the soundtrack of your morning shape your nervous system?', '/cards/card-119.png', '#8a8a85', null),
  (120, 'Inner Peace', 'Safe and Settled',             null, 'I am safe to soften, settle, and stay.', 'What does your soul need to feel safe and settled?', '/cards/card-120.png', '#1f5c3a', null),
  (121, 'Inner Peace', 'Peace Is Created',             null, 'Peace isn''t found; it''s created.', 'What part of your life are you still expecting to deliver peace to you?', '/cards/card-121.png', '#b8922a', null),
  -- May: Confidence
  (122, 'Confidence', 'Qualified, Called, Chosen',     null, 'I am qualified, called, and chosen.', 'What were you sure you couldn''t do that you''ve quietly already done?', '/cards/card-122.png', '#2a1e3f', null),
  (123, 'Confidence', 'Three Things You''re Proud Of', null, 'I am proud of myself for things others may never see.', 'What are three things you''re proud of yourself for?', '/cards/card-123.png', '#a8201f', null),
  (124, 'Confidence', 'Head Held High',                'Walk with your head held high today, on purpose.', 'I carry myself like I belong, because I do.', 'How does your body change when you decide you belong?', '/cards/card-124.png', '#8a8a85', null),
  (125, 'Confidence', 'Dimming Your Light',            null, 'My light is not the problem; their eyes adjust or look away.', 'Where have you been dimming your light to make others comfortable?', '/cards/card-125.png', '#1f5c3a', null),
  (126, 'Confidence', 'Self-Trust in Action',          null, 'Confidence is not ego. It''s self-trust in action.', 'Where is your self-trust quietly ahead of your self-image?', '/cards/card-126.png', '#b8922a', null),
  (127, 'Confidence', 'Born Worthy',                   null, 'I was born worthy. Nothing can take that away.', 'Whose voice still makes you forget you were born worthy?', '/cards/card-127.png', '#2a1e3f', null),
  (128, 'Confidence', '100% Yourself',                 null, 'I bring all of me, every time.', 'What would it be like to show up 100% as yourself today?', '/cards/card-128.png', '#a8201f', null),
  (129, 'Confidence', 'Believe the Compliments',       'Write down three compliments you''ve received and believe them.', 'I let praise land instead of deflecting it.', 'Which compliment have you been hearing for years and never let in?', '/cards/card-129.png', '#8a8a85', null),
  (130, 'Confidence', 'Story of Worth',                null, 'I update my story as fast as I update my growth.', 'What story are you telling yourself that no longer aligns with your worth?', '/cards/card-130.png', '#1f5c3a', null),
  (131, 'Confidence', 'Wrong People',                  null, 'You are not asking for too much; you are just asking the wrong people.', 'Whose limit have you been calling your fault?', '/cards/card-131.png', '#b8922a', null),
  (132, 'Confidence', 'Always Enough',                 null, 'I am enough. I''ve always been enough.', 'Where did you first learn that you weren''t enough, and was that ever true?', '/cards/card-132.png', '#2a1e3f', null),
  (133, 'Confidence', 'Break Up With Beliefs',         null, 'I outgrow beliefs that no longer fit.', 'What limiting beliefs are you ready to break up with?', '/cards/card-133.png', '#a8201f', null),
  (134, 'Confidence', 'Mirror Mantra',                 'Stand in the mirror and say: ''I am powerful. I am enough.''', 'I meet my own eyes without flinching.', 'What did your eyes tell you when you stopped looking away?', '/cards/card-134.png', '#8a8a85', null),
  (135, 'Confidence', 'Speak Like Someone You Love',   null, 'I am someone I love.', 'What would change if you spoke to yourself like someone you love?', '/cards/card-135.png', '#1f5c3a', null),
  (136, 'Confidence', 'Follow Suit',                   null, 'When you believe in yourself, others have no choice but to follow suit.', 'Whose belief in you started with your own?', '/cards/card-136.png', '#b8922a', null),
  (137, 'Confidence', 'Not For Everyone',              null, 'I am not for everyone, and that''s a gift.', 'Who are you actually for, and how does that simplify things?', '/cards/card-137.png', '#2a1e3f', null),
  (138, 'Confidence', 'Uniquely Powerful',             null, 'My particular brand of power is mine alone.', 'What makes you uniquely powerful?', '/cards/card-138.png', '#a8201f', null),
  (139, 'Confidence', 'Wear Power',                    'Wear something today that makes you feel powerful.', 'What I wear announces what I already know about myself.', 'What outfit makes you walk a little differently?', '/cards/card-139.png', '#8a8a85', null),
  (140, 'Confidence', 'Told to Be Small',              null, 'I keep growing past every size someone tried to fit me into.', 'Who told you that you had to be small? Were they ever right?', '/cards/card-140.png', '#1f5c3a', null),
  (141, 'Confidence', 'Worth Beyond Productivity',     null, 'Your worth is not attached to your productivity.', 'Who are you on the days you don''t accomplish anything?', '/cards/card-141.png', '#b8922a', null),
  (142, 'Confidence', 'Divine Confidence',             null, 'I take up space and walk with divine confidence.', 'Where will you take up the space you''ve been ceding?', '/cards/card-142.png', '#2a1e3f', null),
  (143, 'Confidence', 'Permission to Be Great',        null, 'I do not need permission to be who I already am.', 'Where do you still seek permission to be great?', '/cards/card-143.png', '#a8201f', null),
  (144, 'Confidence', 'Smile in the Mirror',           'Smile at yourself every time you walk past a mirror today.', 'I greet myself like good news.', 'What shifts when you become someone who is glad to see you?', '/cards/card-144.png', '#8a8a85', null),
  (145, 'Confidence', 'Apologizing for Brilliance',    null, 'My brilliance is not an apology — it''s an invitation.', 'What would your life look like if you stopped apologizing for your brilliance?', '/cards/card-145.png', '#1f5c3a', null),
  (146, 'Confidence', 'Loud vs. Certain',              null, 'Confidence isn''t about being loud. It''s about being certain.', 'Where is your quiet certainty stronger than someone else''s noise?', '/cards/card-146.png', '#b8922a', null),
  (147, 'Confidence', 'Every Version of Me',           null, 'I honor every version of myself that brought me here.', 'Which past version of you deserves a thank-you note today?', '/cards/card-147.png', '#2a1e3f', null),
  (148, 'Confidence', 'What You''ve Survived',         null, 'What I''ve lived through is now living in my voice.', 'What have you survived that proves your strength?', '/cards/card-148.png', '#a8201f', null),
  (149, 'Confidence', 'Five Wins',                     'List five wins from the last month — big or small.', 'I count my wins because no one else is keeping score for me.', 'Which win do you keep dismissing as ''not really a win''?', '/cards/card-149.png', '#8a8a85', null),
  (150, 'Confidence', 'Most Confident',                null, 'Confidence finds me where I''ve practiced honesty.', 'Where do you feel most confident, and why?', '/cards/card-150.png', '#1f5c3a', null),
  (151, 'Confidence', 'Magnetic Authenticity',         null, 'The most magnetic thing you can be is your authentic self.', 'Where have you been magnetic without trying?', '/cards/card-151.png', '#b8922a', null),
  (152, 'Confidence', 'Becoming Her',                  null, 'I am becoming the woman I used to pray for.', 'Which prayer of your younger self are you currently the answer to?', '/cards/card-152.png', '#2a1e3f', null),
  -- June: Healing
  (153, 'Healing', 'Release What Doesn''t Serve',      null, 'I release what no longer serves me.', 'What chain are you finally ready to set down?', '/cards/card-153.png', '#2a1e3f', null),
  (154, 'Healing', 'Face With Compassion',             null, 'I meet my old pain with grown-up love.', 'What painful memory are you ready to face with compassion?', '/cards/card-154.png', '#a8201f', null),
  (155, 'Healing', 'Safe to Feel',                     'Place your hand on your heart and say: ''I am safe to feel.''', 'I am safe inside my own feelings.', 'Which emotion did you learn was unsafe, and what made it dangerous?', '/cards/card-155.png', '#8a8a85', null),
  (156, 'Healing', 'Lessons You Honor',                null, 'I keep the lessons and release the wounds.', 'What lesson did your past teach you that you now honor?', '/cards/card-156.png', '#1f5c3a', null),
  (157, 'Healing', 'Healing Requires Commitment',      null, 'Your healing doesn''t require permission. It requires commitment.', 'Whose permission have you been waiting for to heal?', '/cards/card-157.png', '#b8922a', null),
  (158, 'Healing', 'Forgive the Not Knowing',          null, 'I forgive myself for not knowing what I didn''t know.', 'Did you do what you could with the information you had at the time?', '/cards/card-158.png', '#2a1e3f', null),
  (159, 'Healing', 'Holding You Back',                 null, 'I open my hands and trust what I''m meant to keep.', 'What are you holding onto that''s holding you back?', '/cards/card-159.png', '#a8201f', null),
  (160, 'Healing', 'Five-Minute Journal',              'Journal for 5 minutes, letting your emotions flow freely.', 'I make room on the page for what I''m not yet ready to say aloud.', 'What surprised you about what came out when you stopped editing?', '/cards/card-160.png', '#8a8a85', null),
  (161, 'Healing', 'Cost of Old Wounds',               null, 'I refuse to pay yesterday''s price in today''s relationships.', 'What is the cost of carrying your old wounds into new spaces?', '/cards/card-161.png', '#1f5c3a', null),
  (162, 'Healing', 'Gift to Yourself',                 null, 'Forgiveness is a gift you give yourself first.', 'Who are you ready to forgive — for your sake, not theirs?', '/cards/card-162.png', '#b8922a', null),
  (163, 'Healing', 'Inner Child',                      null, 'I give my inner child what she always needed.', 'What did your younger self need that no one provided?', '/cards/card-163.png', '#2a1e3f', null),
  (164, 'Healing', 'Younger Self',                     null, 'I am the safe adult my younger self was waiting for.', 'What would your younger self want to hear from you today?', '/cards/card-164.png', '#a8201f', null),
  (165, 'Healing', 'Photo of Her',                     'Find a photo of your younger self. Speak words of love to her.', 'I am gentle with the girl I used to be.', 'What did you see in her face that you usually overlook?', '/cards/card-165.png', '#8a8a85', null),
  (166, 'Healing', 'Rewrite With Grace',               null, 'I revisit my history with the wisdom I have now.', 'What memory needs rewriting with truth and grace?', '/cards/card-166.png', '#1f5c3a', null),
  (167, 'Healing', 'Survivor of It',                   null, 'You are not your trauma. You are the survivor of it.', 'Where are you confusing what happened to you with who you are?', '/cards/card-167.png', '#b8922a', null),
  (168, 'Healing', 'Brave Enough to Heal',             null, 'I am safe to feel and brave enough to heal.', 'What about healing has felt scarier than staying the same?', '/cards/card-168.png', '#2a1e3f', null),
  (169, 'Healing', 'Lives in Your Body',               null, 'My body is a witness, not an enemy.', 'What have you buried that still lives in your body?', '/cards/card-169.png', '#a8201f', null),
  (170, 'Healing', 'Release Letter',                   'Light a candle and write a release letter. Burn or shred it after.', 'I let go ceremonially, with respect for what I''m releasing.', 'What did you write that surprised you, and what did it free?', '/cards/card-170.png', '#8a8a85', null),
  (171, 'Healing', 'Avoided Emotion',                  null, 'I feel what I feel until it has room to leave.', 'What emotion have you been avoiding that''s ready to be felt?', '/cards/card-171.png', '#1f5c3a', null),
  (172, 'Healing', 'Healing Isn''t Linear',            null, 'Healing isn''t linear, but every step is sacred.', 'Where have you judged yourself for backsliding when you were really integrating?', '/cards/card-172.png', '#b8922a', null),
  (173, 'Healing', 'How Far I''ve Come',               null, 'I honor my story and how far I''ve come.', 'What chapter are you in now that you couldn''t have imagined last year?', '/cards/card-173.png', '#2a1e3f', null),
  (174, 'Healing', 'Repeating Patterns',               null, 'I notice the pattern, and I choose differently.', 'What patterns keep repeating from your past?', '/cards/card-174.png', '#a8201f', null),
  (175, 'Healing', 'That Was Then',                    'Speak aloud: ''That was then. This is now. I choose peace.''', 'I live in now.', 'What past moment is your present nervous system still treating as current?', '/cards/card-175.png', '#8a8a85', null),
  (176, 'Healing', 'Closure Without Apology',          null, 'I close chapters that no one will ever close for me.', 'What would closure feel like without needing an apology?', '/cards/card-176.png', '#1f5c3a', null),
  (177, 'Healing', 'Testimony, Not Sentence',          null, 'Your story is a testimony, not a life sentence.', 'Where has your story become evidence instead of a verdict?', '/cards/card-177.png', '#b8922a', null),
  (178, 'Healing', 'Comfort of Old Wounds',            null, 'I no longer shrink for the comfort of old wounds.', 'What old wound have you been keeping comfortable instead of healed?', '/cards/card-178.png', '#2a1e3f', null),
  (179, 'Healing', 'Ready to Release',                 null, 'I thank her, and I let her go.', 'What version of yourself are you finally ready to release?', '/cards/card-179.png', '#a8201f', null),
  (180, 'Healing', 'Shake Off the Residue',            'Stretch and move your body. Shake off emotional residue.', 'My body is a place to leave things, not store them.', 'Which emotion has been hiding in your shoulders this week?', '/cards/card-180.png', '#8a8a85', null),
  (181, 'Healing', 'Differently Now',                  null, 'I am not the woman this used to happen to.', 'How do you show up differently now than in the past?', '/cards/card-181.png', '#1f5c3a', null),
  (182, 'Healing', 'Still Standing',                   null, 'The fact that you''re still standing is evidence of your healing.', 'What about your continued standing surprises even you?', '/cards/card-182.png', '#b8922a', null),
  -- July: Freedom
  (183, 'Freedom', 'Joy as Birthright',                null, 'Joy is my birthright and my daily choice.', 'Where have you been waiting to earn joy that''s already yours?', '/cards/card-183.png', '#2a1e3f', null),
  (184, 'Freedom', 'Last Time Free',                   null, 'I let myself feel free without justifying it.', 'When was the last time you felt truly free?', '/cards/card-184.png', '#a8201f', null),
  (185, 'Freedom', 'Music That Lifts',                 'Start your day with music that lifts your spirit.', 'I curate my mood as carefully as my morning.', 'What song has never failed to shift you?', '/cards/card-185.png', '#8a8a85', null),
  (186, 'Freedom', 'Joy Without Guilt',                null, 'I am allowed to be happy in a hard world.', 'What would it look like to choose joy without guilt?', '/cards/card-186.png', '#1f5c3a', null),
  (187, 'Freedom', 'Joy Is Reason Enough',             null, 'You don''t need a reason to smile. Joy is reason enough.', 'When did you last smile at nothing in particular?', '/cards/card-187.png', '#b8922a', null),
  (188, 'Freedom', 'Play and Explore',                 null, 'I give myself permission to play and explore.', 'What would you try if ''serious'' wasn''t a virtue?', '/cards/card-188.png', '#2a1e3f', null),
  (189, 'Freedom', 'Pure Happiness',                   null, 'I make time for the things that have no other point.', 'What activities bring you pure, unfiltered happiness?', '/cards/card-189.png', '#a8201f', null),
  (190, 'Freedom', 'Dance Freely',                     'Dance freely to one song before starting your day.', 'My body knows how to celebrate without instructions.', 'What did your body say when you let it move without a plan?', '/cards/card-190.png', '#8a8a85', null),
  (191, 'Freedom', 'Inner Child Needs',                null, 'I am responsible for the joy I once asked others to provide.', 'What does your inner child need more of this week?', '/cards/card-191.png', '#1f5c3a', null),
  (192, 'Freedom', 'Found in Authenticity',            null, 'Freedom is found in authenticity.', 'Where would freedom open up if you simply stopped pretending?', '/cards/card-192.png', '#b8922a', null),
  (193, 'Freedom', 'Laugh Loudly, Live Boldly',        null, 'I laugh loudly, live boldly, and love fully.', 'Where have you been quieter than your actual joy?', '/cards/card-193.png', '#2a1e3f', null),
  (194, 'Freedom', 'Stomach Laugh',                    null, 'Laughter is my favorite kind of medicine.', 'What makes you laugh until your stomach hurts?', '/cards/card-194.png', '#a8201f', null),
  (195, 'Freedom', 'Joy Call',                         'Call or message someone who brings you joy.', 'My joy is contagious, and I share it on purpose.', 'Whose name lights you up when it crosses your phone?', '/cards/card-195.png', '#8a8a85', null),
  (196, 'Freedom', 'Full Self',                        null, 'There is no part of me that needs hiding.', 'What''s holding you back from expressing your full self?', '/cards/card-196.png', '#1f5c3a', null),
  (197, 'Freedom', 'Healing and Happy',                null, 'You are allowed to be both healing and happy.', 'Where have you been waiting to finish healing before letting yourself be happy?', '/cards/card-197.png', '#b8922a', null),
  (198, 'Freedom', 'Weight of Expectations',           null, 'I am free from the weight of others'' expectations.', 'Whose expectations have you been carrying as if they were instructions?', '/cards/card-198.png', '#2a1e3f', null),
  (199, 'Freedom', 'Crave More Freedom',               null, 'I move toward freedom even when it''s unfamiliar.', 'Where in your life do you crave more freedom?', '/cards/card-199.png', '#a8201f', null),
  (200, 'Freedom', 'Wear Vibrant',                     'Wear something today that makes you feel vibrant.', 'I let myself stand out because I am here.', 'What color have you been afraid to wear, and why?', '/cards/card-200.png', '#8a8a85', null),
  (201, 'Freedom', 'Beliefs About Joy',                null, 'Joy is allowed to be ordinary, frequent, and mine.', 'What beliefs about joy are you ready to rewrite?', '/cards/card-201.png', '#1f5c3a', null),
  (202, 'Freedom', 'Joy as Protest',                   null, 'Joy is a protest against everything that tried to break you.', 'Where is your joy a quiet act of defiance?', '/cards/card-202.png', '#b8922a', null),
  (203, 'Freedom', 'Small Wins',                       null, 'I celebrate the small wins as much as the big ones.', 'Which small win this week did you almost not let yourself count?', '/cards/card-203.png', '#2a1e3f', null),
  (204, 'Freedom', 'Celebrate Yourself',               null, 'I celebrate myself today, before today is over.', 'What can you celebrate about yourself today?', '/cards/card-204.png', '#a8201f', null),
  (205, 'Freedom', 'Three Things Right',               'List 3 things that went right yesterday.', 'I look for what went right as carefully as what went wrong.', 'What went right that you''ve already forgotten about?', '/cards/card-205.png', '#8a8a85', null),
  (206, 'Freedom', 'Celebration Traditions',           null, 'I do not save celebration for milestones.', 'What traditions can you create around celebration?', '/cards/card-206.png', '#1f5c3a', null),
  (207, 'Freedom', 'Built Moment by Moment',           null, 'Happiness isn''t found. It''s built moment by moment.', 'What moment in this week did you actually live in?', '/cards/card-207.png', '#b8922a', null),
  (208, 'Freedom', 'Space for Joy',                    null, 'I create space for joy to enter and expand.', 'What in your life would have to go to make room for more joy?', '/cards/card-208.png', '#2a1e3f', null),
  (209, 'Freedom', 'Where Joy Lives',                  null, 'Joy lives in me, and I know how to call it forward.', 'Where does joy live in your body? How can you access it today?', '/cards/card-209.png', '#a8201f', null),
  (210, 'Freedom', 'Spontaneous',                      'Do something spontaneous just because it feels good.', 'I follow good feelings without needing them to be useful.', 'What did spontaneity teach you that planning never could?', '/cards/card-210.png', '#8a8a85', null),
  (211, 'Freedom', 'Most Alive',                       null, 'The version of me that is most alive is also the most me.', 'What version of you feels most alive, and how can you return to her?', '/cards/card-211.png', '#1f5c3a', null),
  (212, 'Freedom', 'Living Reminder',                  null, 'You are a living, breathing reminder that joy is possible.', 'Who has told you that your joy gave them permission?', '/cards/card-212.png', '#b8922a', null),
  (213, 'Freedom', 'Sacred and Unstoppable',           null, 'My joy is sacred, sustainable, and unstoppable.', 'What would unstoppable joy look like in your most ordinary day?', '/cards/card-213.png', '#2a1e3f', null),
  -- August: Manifestation
  (214, 'Manifestation', 'Magnet for Alignment',       null, 'I am a magnet for divine opportunities and alignment.', 'What is already moving toward you that you haven''t claimed?', '/cards/card-214.png', '#2a1e3f', null),
  (215, 'Manifestation', 'Living Your Purpose',        null, 'Living in my purpose feels like coming home.', 'What does living in your purpose feel like to you?', '/cards/card-215.png', '#a8201f', null),
  (216, 'Manifestation', 'One Bold Goal',              'Write down one bold goal and one action step to support it.', 'I name what I want and the next step it requires.', 'Which goal scares you exactly enough to be the right one?', '/cards/card-216.png', '#8a8a85', null),
  (217, 'Manifestation', 'Success Guaranteed',         null, 'I act as if I''m already meant for it, because I am.', 'What would you do if you knew success was guaranteed?', '/cards/card-217.png', '#1f5c3a', null),
  (218, 'Manifestation', 'Belief Begins With You',     null, 'Manifestation begins with belief, and belief begins with you.', 'Where is your belief in yourself the bottleneck?', '/cards/card-218.png', '#b8922a', null),
  (219, 'Manifestation', 'Co-Creating With Vision',    null, 'I am co-creating my life with God and vision.', 'Where are you waiting for help instead of partnering with it?', '/cards/card-219.png', '#2a1e3f', null),
  (220, 'Manifestation', 'Calling It In',              null, 'What I call in is on its way to me.', 'What are you calling in this month?', '/cards/card-220.png', '#a8201f', null),
  (221, 'Manifestation', 'Speak to the Mirror',        'Speak your goals out loud while looking in the mirror.', 'Saying it out loud makes it more mine.', 'What did your face do when you heard yourself say what you actually want?', '/cards/card-221.png', '#8a8a85', null),
  (222, 'Manifestation', 'Habits of Becoming',         null, 'I practice the habits of the woman I''m becoming.', 'What habits align with the woman you are becoming?', '/cards/card-222.png', '#1f5c3a', null),
  (223, 'Manifestation', 'Meet It Halfway',            null, 'Your dream life is already seeking you. Meet it halfway.', 'Where is your dream life knocking, and have you been answering?', '/cards/card-223.png', '#b8922a', null),
  (224, 'Manifestation', 'Clear and Committed',        null, 'I am clear, committed, and connected to my purpose.', 'Where do you have clarity that you keep treating like confusion?', '/cards/card-224.png', '#2a1e3f', null),
  (225, 'Manifestation', 'Values Guide Vision',        null, 'I make choices that match my values, not just my goals.', 'What values guide your vision?', '/cards/card-225.png', '#a8201f', null),
  (226, 'Manifestation', 'Read Your Why',              'Write down your ''why'' and read it before you begin your day.', 'My why outlasts every dip in motivation.', 'What is your real why, underneath the polished one?', '/cards/card-226.png', '#8a8a85', null),
  (227, 'Manifestation', 'Where the Magic Is',         null, 'I move toward the part of my vision that scares me most.', 'What part of your vision scares you? That''s where the magic is.', '/cards/card-227.png', '#1f5c3a', null),
  (228, 'Manifestation', 'Purpose Remembered',         null, 'Purpose isn''t found; it''s remembered.', 'What did you know about your purpose at age twelve?', '/cards/card-228.png', '#b8922a', null),
  (229, 'Manifestation', 'Trust the Timing',           null, 'I trust the timing of my life and the unfolding of my path.', 'Where has timing protected you from something you wanted at the wrong moment?', '/cards/card-229.png', '#2a1e3f', null),
  (230, 'Manifestation', 'One Aligned Step',           null, 'Today''s small step is the whole strategy.', 'What''s one step you can take today to align with purpose?', '/cards/card-230.png', '#a8201f', null),
  (231, 'Manifestation', 'Already Arrived',            'Visualize the version of you who has already arrived.', 'She is real, and I am becoming her.', 'What does the arrived version of you do differently in the morning?', '/cards/card-231.png', '#8a8a85', null),
  (232, 'Manifestation', 'Pulling Away From Purpose',  null, 'I notice the distractions and return to what matters.', 'What distractions are pulling you away from your purpose?', '/cards/card-232.png', '#1f5c3a', null),
  (233, 'Manifestation', 'Delay, Not Denial',          null, 'Delay does not mean denial. Stay focused.', 'Where have you read a delay as a denial when it was actually a setup?', '/cards/card-233.png', '#b8922a', null),
  (234, 'Manifestation', 'Once Dreamed About',         null, 'I am becoming the version of me I once dreamed about.', 'Which dream from five years ago is your current reality?', '/cards/card-234.png', '#2a1e3f', null),
  (235, 'Manifestation', 'Faith and Focus',            null, 'I hold faith and focus at the same time.', 'What does it look like to walk in faith and focus?', '/cards/card-235.png', '#a8201f', null),
  (236, 'Manifestation', 'Future Gratitude',           'Write a future gratitude list: ''I''m so grateful I now have…''', 'I am grateful for what is coming as if it has already arrived.', 'What did you write that surprised you with how possible it felt?', '/cards/card-236.png', '#8a8a85', null),
  (237, 'Manifestation', 'Limiting Belief',            null, 'The belief blocking me is not the truth; it''s just the loudest voice.', 'What limiting belief is blocking your next breakthrough?', '/cards/card-237.png', '#1f5c3a', null),
  (238, 'Manifestation', 'Prayer Answered',            null, 'Every step you take in purpose is a prayer answered.', 'Which step you took recently looks, in hindsight, like an answered prayer?', '/cards/card-238.png', '#b8922a', null),
  (239, 'Manifestation', 'Faith, Clarity, Expectation',null, 'I show up with faith, clarity, and expectation.', 'What does showing up ''with expectation'' actually look like for you?', '/cards/card-239.png', '#2a1e3f', null),
  (240, 'Manifestation', 'Vision and Action',          null, 'My actions today reflect tomorrow''s vision.', 'What does alignment between vision and action mean to you?', '/cards/card-240.png', '#a8201f', null),
  (241, 'Manifestation', 'Done List',                  'Write a ''done'' list instead of a to-do list today.', 'I count what I finished, not what''s left.', 'What did your done list reveal about how much you actually do?', '/cards/card-241.png', '#8a8a85', null),
  (242, 'Manifestation', 'Already Manifested',         null, 'I have already done what I once thought I couldn''t.', 'What have you already manifested that once felt impossible?', '/cards/card-242.png', '#1f5c3a', null),
  (243, 'Manifestation', 'Within You, Waiting',        null, 'The life you want is already within you; it''s just waiting to be claimed.', 'Which part of your dream life is waiting only on you to claim it?', '/cards/card-243.png', '#b8922a', null),
  (244, 'Manifestation', 'Boldly, Deeply, Divinely',   null, 'I manifest boldly, love deeply, and move with divine intention.', 'Where is your boldness already pulling your life forward?', '/cards/card-244.png', '#2a1e3f', null),
  -- September: Mindset
  (245, 'Mindset', 'Faith, Not Fear',                  null, 'My thoughts are aligned with faith, not fear.', 'Which fearful thought has had too much airtime lately?', '/cards/card-245.png', '#2a1e3f', null),
  (246, 'Mindset', 'Belief to Challenge',              null, 'I question the beliefs that quietly run my life.', 'What belief do you need to challenge today?', '/cards/card-246.png', '#a8201f', null),
  (247, 'Mindset', 'Expect Good Things',               'Start your day by saying: ''I expect good things to happen.''', 'Good things happen to me, and I notice when they do.', 'How does your day shift when expectation tilts toward good?', '/cards/card-247.png', '#8a8a85', null),
  (248, 'Mindset', 'Thoughts Shape Reality',           null, 'I am the architect of what I keep thinking about.', 'How do your thoughts shape your reality?', '/cards/card-248.png', '#1f5c3a', null),
  (249, 'Mindset', 'Master Your Mindset',              null, 'Master your mindset, and you master your life.', 'Which area of your life is asking for a mindset upgrade?', '/cards/card-249.png', '#b8922a', null),
  (250, 'Mindset', 'Story I Tell Myself',              null, 'I am in control of the story I tell myself.', 'What''s the most generous version of the story you''ve been telling?', '/cards/card-250.png', '#2a1e3f', null),
  (251, 'Mindset', 'Pattern Not Serving',              null, 'I let go of thought patterns the moment they reveal themselves.', 'What thought pattern is no longer serving you?', '/cards/card-251.png', '#a8201f', null),
  (252, 'Mindset', 'Empowering Replacement',           'Replace one limiting belief with an empowering one today.', 'I install thoughts that match the life I want.', 'Which empowering belief did you adopt only after the limiting one stopped fitting?', '/cards/card-252.png', '#8a8a85', null),
  (253, 'Mindset', 'Ground Yourself',                  null, 'I have anchors that hold me when my thoughts don''t.', 'When do your thoughts tend to spiral, and how can you ground yourself?', '/cards/card-253.png', '#1f5c3a', null),
  (254, 'Mindset', 'Believe Everything You Think',     null, 'You don''t have to believe everything you think.', 'Which thought have you been believing simply because it''s familiar?', '/cards/card-254.png', '#b8922a', null),
  (255, 'Mindset', 'Possibility Over Panic',           null, 'I choose possibility over panic.', 'Where has panic crowded out the possibility you couldn''t see?', '/cards/card-255.png', '#2a1e3f', null),
  (256, 'Mindset', 'New Narrative',                    null, 'I narrate my life forward, not just backward.', 'What''s a new narrative you want to start living out?', '/cards/card-256.png', '#a8201f', null),
  (257, 'Mindset', 'Empowering Sentence',              'Write one empowering sentence and repeat it throughout your day.', 'I say what I want to be true until I am.', 'Which sentence repeated changed how you actually moved today?', '/cards/card-257.png', '#8a8a85', null),
  (258, 'Mindset', 'Stuck in Comfort',                 null, 'Comfort is not the same as safety, and I know the difference.', 'What thoughts keep you stuck in your comfort zone?', '/cards/card-258.png', '#1f5c3a', null),
  (259, 'Mindset', 'Powerful Mind, Powerful Life',     null, 'A powerful mind creates a powerful life.', 'Where is your mind already pulling your life forward?', '/cards/card-259.png', '#b8922a', null),
  (260, 'Mindset', 'Doubt to Trust',                   null, 'I release doubt and choose trust.', 'Where has doubt been disguised as wisdom?', '/cards/card-260.png', '#2a1e3f', null),
  (261, 'Mindset', 'Rehearsing in Your Mind',          null, 'I rehearse the future I want, not the one I fear.', 'What are you constantly rehearsing in your mind?', '/cards/card-261.png', '#a8201f', null),
  (262, 'Mindset', 'Mental Check-In',                  'Pause and check in with your mental state before any decision today.', 'I make decisions from clear, not crowded.', 'What decision have you been making from a tired mind that deserves a fresh one?', '/cards/card-262.png', '#8a8a85', null),
  (263, 'Mindset', 'Future, Not Past',                 null, 'I think from where I''m going, not where I''ve been.', 'What would change if you thought from your future, not your past?', '/cards/card-263.png', '#1f5c3a', null),
  (264, 'Mindset', 'Prison or Passport',               null, 'Your mindset is either your prison or your passport.', 'Which mindset are you ready to trade in this month?', '/cards/card-264.png', '#b8922a', null),
  (265, 'Mindset', 'Growth Over Comfort',              null, 'I am committed to growth over comfort.', 'What does growth cost you that comfort never could?', '/cards/card-265.png', '#2a1e3f', null),
  (266, 'Mindset', 'Self-Sabotage',                    null, 'I notice self-sabotage and choose differently in real time.', 'Where do you tend to self-sabotage, and why?', '/cards/card-266.png', '#a8201f', null),
  (267, 'Mindset', 'Speak Life First',                 'Speak life over yourself today before anyone else does.', 'I speak life over myself first thing in the morning.', 'What words have you been waiting for someone else to say to you?', '/cards/card-267.png', '#8a8a85', null),
  (268, 'Mindset', 'One Thought to Let Go',            null, 'I let thoughts pass without making them mine.', 'What is one thought you can let go of today?', '/cards/card-268.png', '#1f5c3a', null),
  (269, 'Mindset', 'Mental Clutter',                   null, 'Clarity begins when mental clutter ends.', 'What mental tab can you finally close today?', '/cards/card-269.png', '#b8922a', null),
  (270, 'Mindset', 'Knows She''s Powerful',            null, 'I think like a woman who knows she''s powerful.', 'How would she — the woman who knows — handle what''s in front of you?', '/cards/card-270.png', '#2a1e3f', null),
  (271, 'Mindset', 'Strong, Aligned Mindset',          null, 'My mindset is calm, certain, and on my side.', 'What does a strong, aligned mindset feel like to you?', '/cards/card-271.png', '#a8201f', null),
  (272, 'Mindset', 'Highest-Self Beliefs',             'Write out 3 beliefs that reflect your highest self.', 'I believe what my highest self believes.', 'Which of those beliefs feels closest to true right now?', '/cards/card-272.png', '#8a8a85', null),
  (273, 'Mindset', 'Limiting the Next Level',          null, 'I outgrow my limits as I notice them.', 'What thought has been limiting your next level?', '/cards/card-273.png', '#1f5c3a', null),
  (274, 'Mindset', 'Change Your Frequency',            null, 'Change your thoughts, change your frequency.', 'What thoughts are you ready to stop broadcasting?', '/cards/card-274.png', '#b8922a', null),
  -- October: Reinvention
  (275, 'Reinvention', 'Rise Every Time',              null, 'I rise every time life tries to knock me down.', 'Where in your life have you risen so often that rising is now your reflex?', '/cards/card-275.png', '#2a1e3f', null),
  (276, 'Reinvention', 'Stronger Through Hurt',        null, 'Pain didn''t end me; it edited me.', 'What challenge made you stronger, even when it hurt?', '/cards/card-276.png', '#a8201f', null),
  (277, 'Reinvention', 'Once Felt Impossible',         'Reflect on one thing you''ve overcome that once felt impossible.', 'I am the proof that what felt impossible was not.', 'What''s the most recent thing you survived that you forgot to be amazed by?', '/cards/card-277.png', '#8a8a85', null),
  (278, 'Reinvention', 'Everyday Resilience',          null, 'My resilience shows up in the boring, daily ways.', 'What does resilience look like in your everyday life?', '/cards/card-278.png', '#1f5c3a', null),
  (279, 'Reinvention', 'Already Survived',             null, 'You''ve already survived your hardest days. Remember that.', 'Which day did you not think you''d live through, and what did you find on the other side?', '/cards/card-279.png', '#b8922a', null),
  (280, 'Reinvention', 'One of a Kind',                null, 'I am not who I was. I am becoming who I''m meant to be.', 'Who are you no longer, and how did you know it was time?', '/cards/card-280.png', '#2a1e3f', null),
  (281, 'Reinvention', 'Evolving Now',                 null, 'I am visibly different from who I was a month ago.', 'What parts of you are evolving right now?', '/cards/card-281.png', '#a8201f', null),
  (282, 'Reinvention', 'Welcome Change',               'Start your day by saying: ''I welcome change as growth.''', 'Change is not happening to me; it''s happening through me.', 'What change are you currently inside of without naming it?', '/cards/card-282.png', '#8a8a85', null),
  (283, 'Reinvention', 'Leave Behind This Season',     null, 'I leave behind what was never meant to come with me.', 'What are you ready to leave behind this season?', '/cards/card-283.png', '#1f5c3a', null),
  (284, 'Reinvention', 'Birthright, Not Breakdown',    null, 'Reinvention is your birthright, not a breakdown.', 'Where have you mistaken reinvention for failure?', '/cards/card-284.png', '#b8922a', null),
  (285, 'Reinvention', 'Bend, Not Break',              null, 'I bend, but I do not break.', 'Which bend in your life is teaching you something rigidity couldn''t?', '/cards/card-285.png', '#2a1e3f', null),
  (286, 'Reinvention', 'Past Taught Strength',         null, 'My past is one of my best teachers.', 'What has your past taught you about your strength?', '/cards/card-286.png', '#a8201f', null),
  (287, 'Reinvention', 'Letter to Future Self',        'Write a letter to your future self, thanking her for not giving up.', 'I write to my future like she''s already real.', 'What did you trust about her that you don''t yet trust about yourself?', '/cards/card-287.png', '#8a8a85', null),
  (288, 'Reinvention', 'Bounce Back Without Bitterness',null, 'I come back fuller, not bitter.', 'What does it look like to bounce back without bitterness?', '/cards/card-288.png', '#1f5c3a', null),
  (289, 'Reinvention', 'Bigger Than Breakdown',        null, 'Your bounce back is always bigger than your breakdown.', 'What did your last breakdown make space for that wouldn''t have fit before?', '/cards/card-289.png', '#b8922a', null),
  (290, 'Reinvention', 'Wiser This Time',              null, 'I am not afraid to start over. This time, I''m wiser.', 'What do you know now about starting over that you wish you''d known then?', '/cards/card-290.png', '#2a1e3f', null),
  (291, 'Reinvention', 'Begin With Boldness',          null, 'I begin again with the confidence of someone who''s already begun.', 'What would it look like to begin again with boldness?', '/cards/card-291.png', '#a8201f', null),
  (292, 'Reinvention', 'One Thing Differently',        'Do one thing differently today and observe how it feels.', 'Small experiments are how I learn what I want.', 'What surprised you about how easy ''different'' actually was?', '/cards/card-292.png', '#8a8a85', null),
  (293, 'Reinvention', 'Bloom With Grace',             null, 'I bloom on my own schedule, with my own grace.', 'Where do you need to give yourself grace during this transformation?', '/cards/card-293.png', '#1f5c3a', null),
  (294, 'Reinvention', 'Power in the Pivot',           null, 'There''s power in your pivot.', 'What pivot are you in right now, and what is it making possible?', '/cards/card-294.png', '#b8922a', null),
  (295, 'Reinvention', 'Endure and Evolve',            null, 'I don''t just endure; I evolve.', 'Where have you been enduring when evolving was actually available?', '/cards/card-295.png', '#2a1e3f', null),
  (296, 'Reinvention', 'Outdated Version',             null, 'I release outdated versions of me with respect.', 'What outdated version of you are you finally releasing?', '/cards/card-296.png', '#a8201f', null),
  (297, 'Reinvention', 'Three Messy Ways',             'List 3 ways you''ve grown this year, even if they were messy.', 'Messy growth still counts.', 'Which messy growth has paid off in ways no one will ever see?', '/cards/card-297.png', '#8a8a85', null),
  (298, 'Reinvention', 'Rewrite Identity',             null, 'I am the author of my own identity.', 'What are you ready to rewrite about your identity?', '/cards/card-298.png', '#1f5c3a', null),
  (299, 'Reinvention', 'Storm Shifts Direction',       null, 'Sometimes the storm was sent to shift your direction.', 'Which storm in your story turned out to be redirection?', '/cards/card-299.png', '#b8922a', null),
  (300, 'Reinvention', 'Stronger, Wiser, Softer',      null, 'I am rebuilding stronger, wiser, and softer.', 'Where has softness become your new strength?', '/cards/card-300.png', '#2a1e3f', null),
  (301, 'Reinvention', 'Pain to Purpose',              null, 'My pain made my purpose more honest.', 'How has pain deepened your capacity for purpose?', '/cards/card-301.png', '#a8201f', null),
  (302, 'Reinvention', 'Breaking Through',             'Speak this aloud: ''I am not broken. I am breaking through.''', 'I am breaking through, not breaking down.', 'What part of you is breaking through right now, even if no one notices yet?', '/cards/card-302.png', '#8a8a85', null),
  (303, 'Reinvention', 'New Standard',                 null, 'I rise to my own standard, not anyone else''s.', 'What new standard are you holding yourself to this season?', '/cards/card-303.png', '#1f5c3a', null),
  (304, 'Reinvention', 'Blueprint to Rise',            null, 'You are the blueprint for what it looks like to rise again.', 'Who is watching you rise and learning that they can too?', '/cards/card-304.png', '#b8922a', null),
  (305, 'Reinvention', 'Still Unfolding',              null, 'My story is still unfolding, and it''s powerful.', 'What chapter of your story are you in right now?', '/cards/card-305.png', '#2a1e3f', null),
  -- November: Gratitude
  (306, 'Gratitude', 'Gratitude and Grace',            null, 'I move with gratitude and receive with grace.', 'Where are you receiving as well as you give?', '/cards/card-306.png', '#2a1e3f', null),
  (307, 'Gratitude', 'Three in This Moment',           null, 'I find gratitude in the moment I''m already in.', 'What are 3 things you''re grateful for in this moment?', '/cards/card-307.png', '#a8201f', null),
  (308, 'Gratitude', 'Gratitude Prayer',               'Start the day with a gratitude prayer or meditation.', 'Gratitude is the first thing I offer the day.', 'How does the day differ when gratitude leads it?', '/cards/card-308.png', '#8a8a85', null),
  (309, 'Gratitude', 'Gratitude and Joy',              null, 'Gratitude and joy share a doorway in me.', 'What has gratitude taught you about joy?', '/cards/card-309.png', '#1f5c3a', null),
  (310, 'Gratitude', 'More Than Enough',               null, 'Gratitude turns what you have into more than enough.', 'Where do you already have more than enough, but it doesn''t feel like it yet?', '/cards/card-310.png', '#b8922a', null),
  (311, 'Gratitude', 'How Far I''ve Come',             null, 'I give myself grace for how far I''ve come.', 'What about your progress is invisible to others but obvious to you?', '/cards/card-311.png', '#2a1e3f', null),
  (312, 'Gratitude', 'Extend Yourself Grace',          null, 'I extend grace to myself in proportion to the load I''m carrying.', 'Where do you need to extend yourself more grace?', '/cards/card-312.png', '#a8201f', null),
  (313, 'Gratitude', 'Doing My Best',                  'I am doing the best I can with what I have.', 'My best changes by the day, and that''s fair.', 'What would change if you trusted that you actually are doing your best?', '/cards/card-313.png', '#8a8a85', null),
  (314, 'Gratitude', 'Release for Peace',              null, 'I trade pressure for peace whenever the trade is offered.', 'What pressure can you release in exchange for peace?', '/cards/card-314.png', '#1f5c3a', null),
  (315, 'Gratitude', 'Grace When Unlovable',           null, 'Grace is giving yourself love even when you feel unlovable.', 'What do you do with yourself on the days you don''t like yourself?', '/cards/card-315.png', '#b8922a', null),
  (316, 'Gratitude', 'Honor and Trust',                null, 'I honor the present and trust the process.', 'What about right now is worth honoring, even if it isn''t where you wanted to be?', '/cards/card-316.png', '#2a1e3f', null),
  (317, 'Gratitude', 'Unexpected Joy',                 null, 'I am awake to the small surprises of being alive.', 'What small moment brought you unexpected joy this week?', '/cards/card-317.png', '#a8201f', null),
  (318, 'Gratitude', 'Letter to Future Self (Gratitude)','Write a letter to your future self, thanking her for not giving up.', 'I write to her like a friend who already exists.', 'What thank-you have you been waiting to receive that you can give yourself?', '/cards/card-318.png', '#8a8a85', null),
  (319, 'Gratitude', 'Bounce Without Bitterness',      null, 'I bounce back gentler, not harder.', 'What does it look like to bounce back without bitterness?', '/cards/card-319.png', '#1f5c3a', null),
  (320, 'Gratitude', 'Attitude, Not Reaction',         null, 'Gratitude is an attitude, not a reaction.', 'Where can gratitude show up before the good news does?', '/cards/card-320.png', '#b8922a', null),
  (321, 'Gratitude', 'Thankful for Becoming',          null, 'I am thankful for the woman I''m becoming.', 'What part of who you''re becoming surprises you?', '/cards/card-321.png', '#2a1e3f', null),
  (322, 'Gratitude', 'Most Proud Growth',              null, 'My growth this year deserves a witness, and I will be one.', 'What growth are you most proud of this year?', '/cards/card-322.png', '#a8201f', null),
  (323, 'Gratitude', 'Challenges Shape Character',     'Reflect on how your challenges have shaped your character.', 'I am made of every challenge I''ve kept walking through.', 'What part of your character was forged in something you didn''t choose?', '/cards/card-323.png', '#8a8a85', null),
  (324, 'Gratitude', 'Grace Flows Through',            null, 'Grace moves through me toward whoever needs it next.', 'What does grace feel like when it flows through your life?', '/cards/card-324.png', '#1f5c3a', null),
  (325, 'Gratitude', 'Rest as Grace',                  null, 'You don''t have to earn rest. Grace gives it freely.', 'What rest have you been postponing until you''ve earned it?', '/cards/card-325.png', '#b8922a', null),
  (326, 'Gratitude', 'Blessings Big and Small',        null, 'I am surrounded by blessings, big and small.', 'Which small blessing in your life has gone uncelebrated?', '/cards/card-326.png', '#2a1e3f', null),
  (327, 'Gratitude', 'Healing Support',                null, 'I am allowed to be carried sometimes.', 'Who or what has supported your healing journey?', '/cards/card-327.png', '#a8201f', null),
  (328, 'Gratitude', 'Gratitude Walk',                 'Do a gratitude walk. Observe everything you''re thankful for.', 'I notice what I have when I move through it slowly.', 'What did you notice on the walk that you usually pass right by?', '/cards/card-328.png', '#8a8a85', null),
  (329, 'Gratitude', 'Once Prayed For',                null, 'I am living inside an answered prayer.', 'What can you celebrate today that you once prayed for?', '/cards/card-329.png', '#1f5c3a', null),
  (330, 'Gratitude', 'Soul Desires',                   null, 'Gratitude attracts more of what your soul desires.', 'What does your soul actually want, beneath the lists?', '/cards/card-330.png', '#b8922a', null),
  (331, 'Gratitude', 'Gift of Today',                  null, 'I embrace the gift of today with a grateful heart.', 'What about today, exactly today, is a gift?', '/cards/card-331.png', '#2a1e3f', null),
  (332, 'Gratitude', 'Live Gracefully',                null, 'I live gracefully even when life is not graceful to me.', 'What does it mean to live gracefully?', '/cards/card-332.png', '#a8201f', null),
  (333, 'Gratitude', 'Light and Speak',                'Light a candle and speak 5 things you''re thankful for.', 'Speaking my thanks aloud makes them more true.', 'Which of the five did you almost not say out loud?', '/cards/card-333.png', '#8a8a85', null),
  (334, 'Gratitude', 'Gentle With Yourself',           null, 'I am gentle with myself first.', 'How can you be more gentle with yourself this week?', '/cards/card-334.png', '#1f5c3a', null),
  (335, 'Gratitude', 'Bridge of Grace',                null, 'Grace is the bridge between who you were and who you''re becoming.', 'Where in your story did grace become the only way through?', '/cards/card-335.png', '#b8922a', null),
  -- December: Wholeness
  (336, 'Wholeness', 'Whole as I Grow',                null, 'I am whole, even as I continue to grow.', 'Where do you keep waiting to feel whole that you actually already are?', '/cards/card-336.png', '#2a1e3f', null),
  (337, 'Wholeness', 'Honor More Fully',               null, 'I honor every part of me, on purpose.', 'What parts of you are you ready to honor more fully?', '/cards/card-337.png', '#a8201f', null),
  (338, 'Wholeness', 'Stillness and Reflection',       'Start the day with stillness and reflect on the year behind you.', 'I look back without losing where I''m going.', 'What does the year look like when you sit with it instead of skim it?', '/cards/card-338.png', '#8a8a85', null),
  (339, 'Wholeness', 'Seeking Outside',                null, 'What I am looking for is on the inside, and I know how to find it.', 'Where have you been seeking outside what only you can give yourself?', '/cards/card-339.png', '#1f5c3a', null),
  (340, 'Wholeness', 'Rediscovering Fullness',         null, 'You are not missing pieces; you are rediscovering your fullness.', 'What have you called missing that''s actually been here all along?', '/cards/card-340.png', '#b8922a', null),
  (341, 'Wholeness', 'How Far and Who',                null, 'I celebrate how far I''ve come and who I''m becoming.', 'What do you know about yourself this year that you didn''t last year?', '/cards/card-341.png', '#2a1e3f', null),
  (342, 'Wholeness', 'Lessons of the Year',            null, 'I am the student of my own life.', 'What lessons did this year teach you about yourself?', '/cards/card-342.png', '#a8201f', null),
  (343, 'Wholeness', 'Three Proud Moments',            'Write down 3 moments this year that made you proud.', 'I let myself be proud of who I am, this year.', 'Which of those three moments did you almost not count?', '/cards/card-343.png', '#8a8a85', null),
  (344, 'Wholeness', 'Internal Change',                null, 'I am changing in ways the world hasn''t caught up to yet.', 'How have you changed internally, even if the world hasn''t seen it yet?', '/cards/card-344.png', '#1f5c3a', null),
  (345, 'Wholeness', 'Depth of Resilience',            null, 'Reflection reveals the depth of your resilience.', 'What does looking back reveal about what you''re actually capable of?', '/cards/card-345.png', '#b8922a', null),
  (346, 'Wholeness', 'Peace and Future',               null, 'I am at peace with my past and in love with my future.', 'What is the gentlest sentence you can say about your past today?', '/cards/card-346.png', '#2a1e3f', null),
  (347, 'Wholeness', 'Old Narratives',                 null, 'I leave old stories at the year''s edge.', 'What old narratives are you leaving behind this year?', '/cards/card-347.png', '#a8201f', null),
  (348, 'Wholeness', 'Letter of Closure',              'Light a candle and write a letter of closure to last year.', 'I close chapters on purpose.', 'What did you finally finish saying to a year that''s almost done?', '/cards/card-348.png', '#8a8a85', null),
  (349, 'Wholeness', 'Emotional Freedom',              null, 'My emotions are mine to feel and free to move through me.', 'What does emotional freedom look like for you now?', '/cards/card-349.png', '#1f5c3a', null),
  (350, 'Wholeness', 'Release as Rebirth',             null, 'Release is a sacred part of rebirth.', 'What''s being born in you that needed something else to leave first?', '/cards/card-350.png', '#b8922a', null),
  (351, 'Wholeness', 'Whole Human Being',              null, 'I am more than my goals. I am a whole human being.', 'Who are you outside of what you''re working on?', '/cards/card-351.png', '#2a1e3f', null),
  (352, 'Wholeness', 'Over-Identified With Productivity',null, 'My value is not measured in checked boxes.', 'Where have you over-identified with productivity this year?', '/cards/card-352.png', '#a8201f', null),
  (353, 'Wholeness', 'Ease Over Hustle',               'Start your day by choosing ease over hustle.', 'I trust ease as a real strategy.', 'What did you accomplish from ease that hustle never could?', '/cards/card-353.png', '#8a8a85', null),
  (354, 'Wholeness', 'Lead With Softness',             null, 'Softness is a leadership skill I''m developing.', 'What would it look like to lead with softness next season?', '/cards/card-354.png', '#1f5c3a', null),
  (355, 'Wholeness', 'Beyond Accomplishments',         null, 'Your worth is not measured by your accomplishments.', 'Who would you be if your worth had nothing to do with what you produced?', '/cards/card-355.png', '#b8922a', null),
  (356, 'Wholeness', 'Into the New Year',              null, 'I carry wisdom, love, and divine strength into the new year.', 'What are you bringing into the new year that you didn''t have a year ago?', '/cards/card-356.png', '#2a1e3f', null),
  (357, 'Wholeness', 'Start of Next Year',             null, 'The version of me at the start of next year is already in motion.', 'Who do you want to be at the start of next year?', '/cards/card-357.png', '#a8201f', null),
  (358, 'Wholeness', 'Theme Word',                     'Write down your theme word or phrase for the year.', 'My theme is mine, not the algorithm''s.', 'What does your word actually mean to you, in your own definition?', '/cards/card-358.png', '#8a8a85', null),
  (359, 'Wholeness', 'Wholeness Now',                  null, 'Wholeness, for me, is the version of me I no longer apologize for.', 'What does wholeness mean to you as this year closes?', '/cards/card-359.png', '#1f5c3a', null),
  (360, 'Wholeness', 'Divine Time',                    null, 'You are not behind. You''re right on divine time.', 'Whose timeline have you been comparing yours to, and is theirs even real?', '/cards/card-360.png', '#b8922a', null),
  (361, 'Wholeness', 'Truth, Grace, Growth',           null, 'I am a full expression of truth, grace, and growth.', 'Where do truth, grace, and growth meet in your life right now?', '/cards/card-361.png', '#2a1e3f', null),
  (362, 'Wholeness', 'Take and Leave',                 null, 'I pack only what I want to keep.', 'What are you taking with you, and what are you leaving behind?', '/cards/card-362.png', '#a8201f', null),
  (363, 'Wholeness', 'Surviving and Thriving',         'I am proud of myself for surviving and thriving.', 'I am proud of myself for both surviving and thriving.', 'Which is harder for you to admit — that you survived, or that you''re now thriving?', '/cards/card-363.png', '#8a8a85', null),
  (364, 'Wholeness', 'One Lesson',                     null, 'I carry one lesson forward like a compass.', 'What is one lesson this year taught you that you''ll never forget?', '/cards/card-364.png', '#1f5c3a', null),
  (365, 'Wholeness', 'Becoming and Being',             null, 'There is beauty in becoming, but peace in simply being.', 'Where will you simply be, this final week of the year?', '/cards/card-365.png', '#b8922a', null)
on conflict (day_number) do update set
  theme          = excluded.theme,
  title          = excluded.title,
  body_text      = excluded.body_text,
  affirmation    = excluded.affirmation,
  journal_prompt = excluded.journal_prompt,
  image_url      = excluded.image_url,
  card_color     = excluded.card_color,
  emoji          = excluded.emoji;
